namespace sv_2111f8a572754a55826b628063b0798b.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_2111f8a572754a55826b628063b0798b.Services

<div class="card h-100 product-card" style="cursor:pointer;" @onclick="HandleCardClick">
    <div class="card-img-top bg-secondary d-flex align-items-center justify-content-center"
         style="height:180px; color:#ccc; font-size:0.9rem;"
         title="@Product.Name">
        @Product.Name
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-success fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@Product.Rating.ToString("0.0") out of 5">
            @GetStarRating(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-primary btn-sm mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);

    private static string GetStarRating(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

@using sv_2111f8a572754a55826b628063b0798b.Services

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="product"
                         OnSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@using sv_2111f8a572754a55826b628063b0798b.Services

<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Category</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@_selectedCategories.Contains(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice" @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice" @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3 form-check">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly" @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public ProductFilter? CurrentFilter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    protected override void OnParametersSet()
    {
        if (CurrentFilter is not null)
        {
            _selectedCategories = CurrentFilter.Categories is not null
                ? new HashSet<string>(CurrentFilter.Categories)
                : [];
            _minPrice = CurrentFilter.MinPrice;
            _maxPrice = CurrentFilter.MaxPrice;
            _inStockOnly = CurrentFilter.InStockOnly;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            _minPrice,
            _maxPrice,
            _inStockOnly);
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@page "/catalog"
@rendermode InteractiveServer
@using sv_2111f8a572754a55826b628063b0798b.Components.Catalog
@using sv_2111f8a572754a55826b628063b0798b.Services
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="_categories"
                            CurrentFilter="_filter"
                            OnFilterApplied="HandleFilterApplied" />
        </div>

        <div class="col-md-9">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result?.TotalCount ?? 0"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products...</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <p class="fs-5">No products found.</p>
                    <p>Try adjusting your filters.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (TotalPages > 1)
                {
                    <div class="mt-4">
                        <CatalogPagination CurrentPage="_currentPage"
                                           TotalPages="TotalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            _result = searchTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryAsync() => await LoadDataAsync();
}

